mapper.update:
UPDATE scenic_spot
SET spot_name=#{spotName}, max_capacity=#{maxCapacity}, total_parking=#{totalParking},
    address=#{address}, longitude=#{longitude}, latitude=#{latitude}, map_url=#{mapUrl}
WHERE id=#{id}

UPDATE scenic_real_time_data
SET current_visitors=#{currentVisitors}, remaining_parking=#{remainingParking}, cable_wait_time=#{cableWaitTime}
WHERE spot_id=#{spotId}
